# app/models/schemas.py
from pydantic import BaseModel, Field, field_validator
from typing import Literal

class Message(BaseModel):
    role: Literal["user", "assistant", "system"]
    content: str = Field(min_length=1, max_length=32_768)

class ChatRequest(BaseModel):
    messages: list[Message] = Field(min_length=1, max_length=50)
    model: str = Field(default="claude-sonnet-4-6")
    max_tokens: int = Field(default=1024, ge=1, le=8192)
    temperature: float = Field(default=0.7, ge=0.0, le=1.0)
    stream: bool = Field(default=True)

    @field_validator("messages")
    @classmethod
    def last_message_must_be_user(cls, messages: list[Message]) -> list[Message]:
        if messages[-1].role != "user":
            raise ValueError("Last message must have role 'user'")
        return messages

class ChatResponse(BaseModel):
    id: str
    content: str
    model: str
    usage: dict[str, int]

# app/api/health.py
from fastapi import APIRouter, status
from fastapi.responses import JSONResponse
from app.services import db, redis_client
from app.config import settings
import anthropic

router = APIRouter(tags=["ops"])

@router.get("/health")
async def liveness():
    return {"status": "ok"}

@router.get("/ready")
async def readiness():
    checks = {}
    ok = True

    try:
        await redis_client.ping()
        checks["redis"] = "ok"
    except Exception as e:
        checks["redis"] = str(e)
        ok = False

    try:
        await db.execute("SELECT 1")
        checks["postgres"] = "ok"
    except Exception as e:
        checks["postgres"] = str(e)
        ok = False

    # Validate API key exists (do not make a real call to avoid cost)
    checks["llm_key"] = "ok" if settings.anthropic_api_key else "missing"
    if not settings.anthropic_api_key:
        ok = False

    code = status.HTTP_200_OK if ok else status.HTTP_503_SERVICE_UNAVAILABLE
    return JSONResponse(content={"status": "ok" if ok else "degraded", "checks": checks}, status_code=code)
